 1→<?php
 2→
 3→namespace Eliberty\RedpillBundle\ExternalActivity;
 4→
 5→class ExternalActivityHandlerFactory
 6→{
 7→    protected array $mapping = [];
 8→
 9→    public function add(ExternalActivityHandlerInterface $processor, $serviceId)
10→    {
11→        $this->mapping[$serviceId] = $processor;
12→    }
13→
14→    private function getServiceId($str, array $noStrip = []): string
15→    {
16→        $str = strtolower($str);
17→        // non-alpha and non-numeric characters become spaces
18→        $str = preg_replace('/[^a-z0-9'.implode('', $noStrip).']+/i', ' ', $str);
19→        $str = trim($str);
20→        // uppercase the first character of each word
21→        $str = ucwords($str);
22→        $str = str_replace(' ', '', $str);
23→
24→        return sprintf('Eliberty\RedpillBundle\ExternalActivity\%s\Rest\%sHandler', $str, $str);
25→    }
26→
27→    public function getHandler(string $name): ExternalActivityHandlerInterface
28→    {
29→        $serviceId = $this->getServiceId($name);
30→
31→        if (!\array_key_exists($serviceId, $this->mapping)) {
32→            throw new \UnexpectedValueException(sprintf('ExternalActivity handler not found for %s', $serviceId));
33→        }
34→
35→        return $this->mapping[$serviceId];
36→    }
37→}
