  1→<?php
  2→
  3→namespace Eliberty\RedpillBundle\ExternalActivity\Helpers;
  4→
  5→use Doctrine\ORM\EntityManagerInterface;
  6→use Eliberty\ConfigManagerBundle\Model\ConfigManager;
  7→use Eliberty\RedpillBundle\Entity\ExternalBooking;
  8→use Eliberty\RedpillBundle\Entity\WebInstance;
  9→use Eliberty\RedpillBundle\Enum\ProductType;
 10→use Eliberty\RedpillBundle\Model\Order;
 11→use Eliberty\RedpillBundle\Util\CacheUtils;
 12→use GuzzleHttp\Exception\RequestException;
 13→use Psr\Log\LoggerInterface;
 14→
 15→class BaseApiHelper
 16→{
 17→    protected LoggerInterface $loggerBooking;
 18→    protected EntityManagerInterface $em;
 19→    protected ConfigManager $configManager;
 20→
 21→    public function __construct(ConfigManager $configManager, EntityManagerInterface $em, LoggerInterface $loggerBooking)
 22→    {
 23→        $this->loggerBooking = $loggerBooking;
 24→        $this->em            = $em;
 25→        $this->configManager = $configManager;
 26→    }
 27→
 28→    public function parseAndLogRequestException(string $functionName, RequestException $requestException): string
 29→    {
 30→        $error = null === $requestException->getResponse() ? 'no response' : json_decode($requestException->getResponse()->getBody(), true);
 31→
 32→        $this->loggerBooking->error("Error during $functionName", ['error' => $error]);
 33→
 34→        if (\is_array($error)) {
 35→            $error = $error['message'] ?? '';
 36→        }
 37→
 38→        return $error ?? '';
 39→    }
 40→
 41→    public function parseAndLogException(string $functionName, \Exception $e): string
 42→    {
 43→        $error = $e->getMessage();
 44→
 45→        $this->loggerBooking->error("Error during $functionName", ['error' => $error]);
 46→
 47→        return $error;
 48→    }
 49→
 50→    public function getRedisKey(string $key, string $path, array $params): string
 51→    {
 52→        $mergeParam = \array_merge(
 53→            [
 54→                'path' => $path,
 55→            ],
 56→            $params
 57→        );
 58→
 59→        return md5('subcontingent__'.$key.'_'.CacheUtils::computeKey($mergeParam));
 60→    }
 61→
 62→    public function logInfo(string $message, array $context = []): void
 63→    {
 64→        $this->loggerBooking->info($message, $context);
 65→    }
 66→
 67→    protected function getWebinstance()
 68→    {
 69→        return $this->em->getRepository(WebInstance::class)->getWebinstance();
 70→    }
 71→
 72→    protected function getBookerName(string $param, Order $order, ExternalBooking $externalBooking): ?string
 73→    {
 74→        $result = ExternalBooking::DEFAULT_NAME;
 75→
 76→        if (!$externalBooking->isDefaultName($param)) {
 77→            $methodOrder = 'getAuthor'.ucfirst($param);
 78→            if (\is_callable([$externalBooking, $methodOrder])) {
 79→                $result = $externalBooking->$methodOrder();
 80→            }
 81→        }
 82→
 83→        // 1 - Get Booker name with contact payer or set Default Name
 84→        if ($externalBooking->isDefaultName($param)) {
 85→            $methodOrder = 'get'.ucfirst($param);
 86→            if (\is_callable([$order, $methodOrder])) {
 87→                $result = $order->$methodOrder() ?? ExternalBooking::DEFAULT_NAME;
 88→            }
 89→        }
 90→
 91→        // 2 - Get Booker Name with datacustom
 92→        if (ExternalBooking::DEFAULT_NAME === $result && $externalBooking->isDefaultName($param)) {
 93→            $result = $order->getDatumcustom($param) ?? ExternalBooking::DEFAULT_NAME;
 94→        }
 95→
 96→        // 3 - Get Booker Name with first participant
 97→        if (ExternalBooking::DEFAULT_NAME === $result && $externalBooking->isDefaultName($param)) {
 98→            $items = $order->getItemsByType(ProductType::$typesWithValidity);
 99→
100→            if ($items->count() > 0) {
101→                $firstTicket = $items->first();
102→
103→                $method = 'get'.ucfirst($param);
104→                if (\is_callable([$firstTicket, $method])) {
105→                    $result = $firstTicket->$method() ?? ExternalBooking::DEFAULT_NAME;
106→                }
107→            }
108→        }
109→
110→        return $result;
111→    }
