 21→/**
 22→ * Class BookingHelper.
 23→ */
 24→class BookingHelper
 25→{
 26→    private EntityManagerInterface $em;
 27→
 28→    public function __construct(EntityManagerInterface $entityManager)
 29→    {
 30→        $this->em = $entityManager;
 31→    }
 32→
 33→    public function groupItemsBySubContingent(CartInterface $cart): array
 34→    {
 35→        $itemsGroupedBySubContingent = [];
 36→        $orderItems                  = $cart->getItemsWithSubContingents();
 37→
 38→        /** @var TicketOrderitem $item */
 39→        foreach ($orderItems as $item) {
 40→            if (!$item instanceof TicketOrderitem && ProductType::ATTRACTION !== $item->getType()) {
 41→                continue;
 42→            }
 43→
 44→            $subContingentId   = $item->getDatum('subContingentId');
 45→            $externalBookingId = $item->getDatum('externalBookingId');
 46→            /** @var Product $product */
 47→            $product = $item->getProduct();
 48→
 49→            if (null === $product->getExternalBookingProvider()) {
 50→                continue;
 51→            }
 52→
 53→            $provider = $product->getExternalBookingProvider();
 54→            $key      = sprintf('%s_%s', $subContingentId, $provider);
 55→
 56→            /** @var ?SubContingent $subContingent */
 57→            $subContingent = $this->em->getRepository(SubContingent::class)->findOneBy([
 58→                'externalId' => $subContingentId,
 59→                'type'       => $provider,
 60→            ]);
 61→
 62→            if ($this->groupAttractionsForAxBooking(
 63→                $item,
 64→                $provider,
 65→                $subContingent,
 66→                $itemsGroupedBySubContingent)
 67→            ) {
 68→                continue;
 69→            }
 70→
 71→            if (!isset($itemsGroupedBySubContingent[$key])) {
 72→                $subContingentDate = null !== $subContingent ? $subContingent->getDate() : $item->getStartdate();
 73→
 74→                $itemsGroupedBySubContingent[$key] = (new SubContingentData())
 75→                    ->setProduct($product)
 76→                    ->setSubContingentId($subContingentId)
 77→                    ->setExternalBookingId($externalBookingId)
 78→                    ->setDate($subContingentDate);
 79→            }
 80→
 81→            $itemsGroupedBySubContingent[$key]
 82→                ->setQty($itemsGroupedBySubContingent[$key]->getQty() + 1)
 83→                ->addOrderItem($item);
 84→        }
 85→
 86→        return $itemsGroupedBySubContingent;
 87→    }
 88→
 89→    public function groupItemsByExternalBooking(Order $order): array
 90→    {
 91→        $itemsWithExternalBooking = $order->getItemsWithExternalBookings();
 92→
 93→        $itemsGroupedByExternalBookings = [];
 94→
 95→        /** @var Orderitem $item */
 96→        foreach ($itemsWithExternalBooking as $item) {
 97→            $arrayKey          = [];
 98→            $product           = $item->getProduct();
 99→            $externalBookingId = $item->getDatum('externalBookingId');
100→
101→            $arrayKey[] = $externalBookingId;
102→            if ($subContingentId = $item->getDatum('subContingentId')) {
103→                $arrayKey[] = $subContingentId;
104→            }
105→            $arrayKey[] = $product->getExternalBookingProvider();
106→            $key        = implode('_', $arrayKey);
107→
108→            if (!isset($itemsGroupedByExternalBookings[$key])) {
109→                $itemsGroupedByExternalBookings[$key] = (new ExternalBookingData())
110→                    ->setExternalBookingId($externalBookingId)
111→                    ->setProduct($item->getProduct())
112→                    ->setFirstOrderItem($item);
113→            }
114→        }
115→
116→        return $itemsGroupedByExternalBookings;
117→    }
118→
119→    public function isAllowedToSynchronizeBooking(Order $order): bool
120→    {
121→        $orderStateList = [
122→            OrderState::CART,
123→            OrderState::PERSONNALIZATION,
124→            OrderState::DELIVERY,
125→            OrderState::ORDER,
126→            OrderState::ORDER_CONFIRMED,
127→        ];
128→
129→        if (!\in_array($order->getState(), $orderStateList, true)) {
130→            return false;
131→        }
132→
133→        $itemsGroupedByExternalBookings = $this->groupItemsByExternalBooking($order);
134→
135→        if (0 === \count($itemsGroupedByExternalBookings)) {
136→            return false;
137→        }
138→
139→        return true;
140→    }
141→
142→    public function isAllowedToCreateBooking(CartInterface $cart): bool
143→    {
144→        if (true === $cart->isSimulation() || OrderState::CART !== $cart->getState()) {
145→            return false;
146→        }
147→
148→        $items = $this->groupItemsBySubContingent($cart);
149→
150→        return 0 !== \count($items);
151→    }
152→
153→    public function isAllowedToConfimBooking(Order $order): bool
154→    {
155→        $orderStateList = [
156→            OrderState::ORDER,
157→            OrderState::ORDER_CONFIRMED,
158→        ];
159→
160→        if (!\in_array($order->getState(), $orderStateList, true)) {
161→            return false;
162→        }
163→
164→        $itemsGroupedByExternalBookings = $this->groupItemsByExternalBooking($order);
165→
166→        if (0 === \count($itemsGroupedByExternalBookings)) {
167→            return false;
168→        }
169→
170→        return true;
171→    }
172→
173→    /**
174→     * Convert string date to DateTime.
175→     */
176→    public function getDateTimeFromString(string $date = null, bool $forceNow = false): ?\DateTime
177→    {
178→        if (empty($date)) {
179→            return $forceNow ? new \DateTime() : null;
180→        }
181→
182→        try {
183→            return new \DateTime($date, new \DateTimeZone('UTC'));
184→        } catch (\Exception $err) {
185→            return $forceNow ? new \DateTime() : null;
186→        }
187→    }
188→
189→    public function getSubContingentSerializer(): Serializer
190→    {
191→        $normalizer = new ObjectNormalizer();
192→        $normalizer->setCallbacks([
193→            'date' => function (\DateTime $dateTime) {
194→                return $dateTime->format('Y-m-d\TH:i:s').'+00:00';
195→            },
196→            'salesClosedAt' => function (\DateTime $dateTime) {
197→                return $dateTime->format('Y-m-d\TH:i:s').'+00:00';
198→            },
199→        ]);
200→
201→        $normalizer->setIgnoredAttributes(['webinstance', 'externalBookings', 'createdat', 'updatedat']);
202→
203→        return new Serializer([$normalizer], [new JsonEncoder()]);
204→    }
205→
206→    public function groupAttractionsForAxBooking(
207→        Orderitem $item,
208→        string $provider,
209→        ?SubContingent $subContingent,
210→        array &$itemsGroupedBySubContingent): bool
211→    {
212→        if (ExternalBookingProvider::AX_BOOKING !== $provider || null === $item->getParent()
213→                || ProductType::ATTRACTION !== $item->getProduct()->getType()) {
214→            return false;
215→        }
216→
217→        // Add many subcontingent with same key to group attraction together
218→        $key = sprintf('%s_%s', $item->getParent()->getId(), $provider);
219→
220→        if (!isset($itemsGroupedBySubContingent[$key])) {
221→            $itemsGroupedBySubContingent[$key] = [];
222→        }
223→
224→        $itemsGroupedBySubContingent[$key][] = (new SubContingentData())
225→            ->setProduct($item->getProduct())
226→            ->setSubContingentId($item->getDatum('subContingentId'))
227→            ->setExternalBookingId($item->getDatum('externalBookingId'))
228→            ->setDate(null !== $subContingent ? $subContingent->getDate() : $item->getStartdate())
229→            ->setQty(1)
230→            ->addOrderItem($item);
231→
232→        return true;
233→    }
234→}
