 54→    /**
 55→     * @throws MissingExternalIdException
 56→     * @throws InvalidArgumentException
 57→     */
 58→    public function getSubContingentsBetweenDates(Product $product, \DateTime $startDate, ?\DateTime $endDate): array
 59→    {
 60→        /** @var VariantInterface|null $variant */
 61→        $variant = $product->getVariants()->filter(function (VariantInterface $variant) {
 62→            return $variant->isActive() && null !== $variant->getExternalId();
 63→        })->first();
 64→
 65→        if (!$variant) {
 66→            throw new MissingExternalIdException(sprintf('Product %d does not have a variant with an external id', $product->getId()));
 67→        }
 68→
 69→        if (null === $endDate) {
 70→            $endDate = $startDate;
 71→        }
 72→
 73→        $key = sprintf('%d-%s-%s', $variant->getId(), $startDate->format('Y-m-d'), $endDate->format('Y-m-d'));
 74→        $key = 'axbooking_'.hash('md5', $key); //NOSONAR
 75→
 76→        if (!$response = $this->cache->get($key)) {
 77→            /** @var SaleschannelConfiguration $salesChannelConfiguration */
 78→            $salesChannelConfiguration = $this->em->getRepository(SaleschannelConfiguration::class)
 79→                ->findOneBy(['catalog' => $product->getCatalog()->getId()]);
 80→
 81→            /* getSaleschannelExternalid should not return int values  */
 82→            $data = [
 83→                'saleschannel' => (int) $salesChannelConfiguration->getSaleschannelExternalid(),
 84→                'product'      => $variant->getExternalid(),
 85→                'startdate'    => $startDate->format('Y-m-d'),
 86→                'enddate'      => $endDate->format('Y-m-d'),
 87→            ];
 88→
 89→            $response = $this->client->getBookingInfo($data);
 90→
 91→            $cacheTime = $this->apiHelper->getCacheExpirationTime();
 92→            if ($cacheTime > 0) {
 93→                $this->cache->set($key, $response, $cacheTime);
 94→            }
 95→        }
 96→
 97→        return $this->apiHelper->getSubContingents($response)->toArray();
 98→    }
 99→
100→    /**
101→     * @throws MissingExternalIdException
102→     * @throws ExternalActivityException
103→     * @throws InvalidArgumentException
104→     */
105→    public function getSubContingent(Product $product, \DateTime $startDate, string $subContingentId, ?bool $withCache = false): ?SubContingent
106→    {
107→        $subContingent = $this->apiHelper->getSubContingent($subContingentId);
108→        if ($subContingent instanceof SubContingent) {
109→            return $subContingent;
110→        }
111→
112→        $subContingents = $this->getSubContingentsBetweenDates($product, $startDate, null);
113→
114→        if (!\array_key_exists($subContingentId, $subContingents)) {
115→            throw new ExternalActivityException(sprintf('Sub contingent with id %s not found', $subContingentId));
116→        }
117→
118→        return $subContingents[$subContingentId];
119→    }
