121→    /**
122→     * @throws MissingExternalIdException
123→     * @throws ExternalActivityException
124→     */
125→    public function createBooking(Order $order, SubContingentData $subContingentData): ExternalBooking
126→    {
127→        $product = $subContingentData->getProduct();
128→
129→        /** @var VariantInterface|null $variant */
130→        $variant = $product->getVariants()->filter(function (VariantInterface $variant) {
131→            return $variant->isActive() && null !== $variant->getExternalId();
132→        })->first();
133→
134→        if (!$variant) {
135→            throw new MissingExternalIdException(sprintf('Product %d does not have a variant with an external id', $product->getId()));
136→        }
137→
138→        /** @var SaleschannelConfiguration $salesChannelConfiguration */
139→        $salesChannelConfiguration = $this->em->getRepository(SaleschannelConfiguration::class)
140→            ->findOneBy(['catalog' => $product->getCatalog()->getId()]);
141→
142→        [$configNo, $configLimitNo, $slotlfdnr] = explode('-', $subContingentData->getSubContingentId());
143→
144→        /* getSaleschannelExternalid should not return int values  */
145→        $data = [
146→            'saleschannel'  => (int) $salesChannelConfiguration->getSaleschannelExternalid(),
147→            'product'       => $variant->getExternalid(),
148→            'countbooking'  => $subContingentData->getQty(),
149→            'configno'      => (int) $configNo,
150→            'configlimitno' => (int) $configLimitNo,
151→            'slotlfdnr'     => (int) $slotlfdnr,
152→        ];
153→
154→        try {
155→            /** @var Result $response */
156→            $response = $this->client->create($data);
157→
158→            if (0 !== $response['error']) {
159→                throw new ExternalActivityException('AX Booking error - Unable to create Ax Booking');
160→            }
161→
162→            return $this->apiHelper->createExternalBooking((string) $response['reservation'], $subContingentData, $order);
163→        } catch (CommandException | \Exception $e) {
164→            $this->apiHelper->parseAndLogException(__METHOD__, $e);
165→
166→            throw new ExternalActivityException($e->getMessage());
167→        }
168→    }
