172→     * @throws ExternalActivityException
173→     */
174→    public function createGroupedBooking(Order $order, array $subContingentArrayData): array
175→    {
176→        $data = $this->createAttractionsDataFromSubcontingents($subContingentArrayData);
177→
178→        if (empty($data['attractions'])) {
179→            return [];
180→        }
181→
182→        $parentSalesChannelConfiguration = $this->em->getRepository(SaleschannelConfiguration::class)->findOneBy([
183→            'catalog' => $subContingentArrayData[0]->getOrderItems()->first()->getParent()->getCatalog()->getId(),
184→        ]);
185→
186→        return $this->createReservationFromTrinity(
187→            $data,
188→            (string) $parentSalesChannelConfiguration->getSaleschannelExternalid(),
189→            $subContingentArrayData,
190→            $order
191→        );
