206→    public function findBooking(string $externalBookingId, WebInstance $webInstance, ?OrderitemInterface $item = null): ?ExternalBooking
207→    {
208→        if (null === $item) {
209→            throw new ExternalActivityException('Orderitem not found');
210→        }
211→
212→        if (!$subContingentId = $item->getDatum('subContingentId')) {
213→            throw new ExternalActivityException('No subContingentId AxBooking found in order item '.$item->getId());
214→        }
215→
216→        $criterias = [
217→            'externalId'  => $subContingentId,
218→            'webinstance' => $webInstance,
219→        ];
220→
221→        $subContingent = $this->em->getRepository(SubContingent::class)->findOneBy($criterias);
222→
223→        $criterias = [
224→            'externalId'    => $externalBookingId,
225→            'subContingent' => $subContingent,
226→            'webinstance'   => $webInstance,
227→        ];
228→
229→        /** @var ExternalBooking|null $booking */
230→        $booking = $this->em->getRepository(ExternalBooking::class)->findOneBy($criterias, ['id' => 'DESC']);
231→
232→        if (null === $booking) {
233→            $this->apiHelper->logInfo('no booking found for this externalBookingId in redpill database.', $criterias);
234→            $this->apiHelper->logInfo('Call booking application to check if this order exist', ['booking_id' => $externalBookingId]);
235→        }
236→
237→        return $booking;
238→    }
239→
240→    private function findFirstMachingOrderitem(Order $order, ExternalBooking $externalBooking): ?OrderitemInterface
241→    {
242→        $items = $order->getItemsWithExternalBookings()->filter(function (OrderitemInterface $item) use ($externalBooking) {
243→            /** @var Orderitem|TicketOrderitem $item */
244→            if (null === $externalBooking->getSubContingent()) {
245→                return $externalBooking->getExternalId() === $item->getDatum('externalBookingId');
246→            }
247→
248→            return $externalBooking->getExternalId() === $item->getDatum('externalBookingId')
249→                && $externalBooking->getSubContingent()->getExternalId() === $item->getDatum('subContingentId');
250→        });
251→
252→        if (0 === $items->count()) {
253→            $this->apiHelper->logInfo('No orderitem found (one expected) for externalBooking '.$externalBooking->getId());
254→        }
255→
256→        return $items->first() ?: null;
257→    }
258→
259→    private function createAttractionsDataFromSubcontingents(array $subContingentArrayData): array
260→    {
261→        $data = [
262→            'attractions' => [],
263→        ];
264→
265→        /** @var SubContingentData $subContingentData */
266→        foreach ($subContingentArrayData as $subContingentData) {
267→            [$configNo, $configLimitNo, $slotlfdnr] = explode('-', $subContingentData->getSubContingentId());
268→            $data['attractions'][]                  = [
269→                'timeslot' => [
270→                    'configno'      => (int) $configNo,
271→                    'configlimitno' => (int) $configLimitNo,
272→                    'slotlfdnr'     => (int) $slotlfdnr,
273→                ],
274→                'count' => $subContingentData->getQty(),
275→            ];
276→        }
277→
278→        return $data;
279→    }
