281→    /**
282→     * @throws ExternalActivityException
283→     */
284→    private function createReservationFromTrinity(array $data, string $salesChannelId, array $subContingentArrayData, Order $order): array
285→    {
286→        try {
287→            $response = $this->axBookingTrinityApiClient->postReservations($data, $salesChannelId);
288→
289→            if (0 !== $response['error']) {
290→                throw new ExternalActivityException('AX Booking error - Unable to create Ax Booking');
291→            }
292→
293→            $externalBookings = [];
294→            /** @var SubContingentData $subContingentData */
295→            foreach ($subContingentArrayData as $subContingentData) {
296→                $externalBookings[$subContingentData->getSubContingentId()] = $this->apiHelper->createExternalBooking((string) $response['reservation'], $subContingentData, $order);
297→            }
298→
299→            return $externalBookings;
300→        } catch (CommandException|\Exception $e) {
301→            $this->apiHelper->parseAndLogException(__METHOD__, $e);
302→            throw new ExternalActivityException($e->getMessage());
303→        }
304→    }
305→}
