 52→            $client     = $this->restFactory->getClient();
 53→            $params     = $this->apiHelper->getParamDaysAvailability();
 54→            $cacheKey   = $this->apiHelper->getRedisKey('booking_days', $path, $params);
 55→
 56→            $this->apiHelper->logInfo('getDaysAvailability for booking with params', $params);
 57→
 58→            if (!$days = $this->redisCache->get($cacheKey)) {
 59→                $res = $client->get($path, ['query' => $params]);
 60→
 61→                $response = json_decode($res->getBody(), true);
 62→                $days     = $this->apiHelper->getListOfDays($response);
 63→
 64→                if ($this->apiHelper->getCacheExpirationTime() > 0) {
 65→                    $this->redisCache->set($cacheKey, $days, $this->apiHelper->getCacheExpirationTime());
 66→                }
 67→            }
 68→
