 19→/**
 20→ * Class ApiHelper.
 21→ */
 22→class ApiHelper extends BaseApiHelper
 23→{
 24→    public const BOOKING_ORDERSTATE_INIT      = 'init';
 25→    public const BOOKING_ORDERSTATE_CART      = 'cart';
 26→    public const BOOKING_ORDERSTATE_CONFIRMED = 'confirmed';
 27→    public const BOOKING_TYPE_PUBLIC          = 'public';
 28→
 29→    public function __construct(ConfigManager $configManager, EntityManagerInterface $em, Logger $loggerBooking)
 30→    {
 31→        parent::__construct($configManager, $em, $loggerBooking);
 32→    }
 33→
 34→    public function getListOfDays(array $bookingDays): array
 35→    {
 36→        $days = [];
 37→
 38→        if (0 !== \count($bookingDays) && !\array_key_exists('error', $bookingDays)) {
 39→            foreach ($bookingDays as $bookingDay) {
 40→                if (!\in_array($bookingDay['date'], $days)) {
 41→                    $days[] = $bookingDay['date'];
 42→                }
 43→            }
 44→        }
 45→
 46→        return $days;
 47→    }
 48→
 49→    /**
 50→     * @param array $bookingActivites
 51→     *
 52→     * @return ArrayCollection<SubContingent>
 53→     *
 54→     * @throws \Exception
 55→     */
 56→    public function getSubContingents(array $bookingActivites): ArrayCollection
 57→    {
 58→        $list = new ArrayCollection();
 59→
 60→        foreach ($bookingActivites as $bookingActivity) {
 61→            $subContingent = $this->serializeSubContingentResponse($bookingActivity);
 62→            $list->add($subContingent);
 63→        }
 64→
 65→        return $list;
 66→    }
 67→
 68→    /**
 69→     * @param array $response
 70→     *
 71→     * @return SubContingent
 72→     *
 73→     * @throws \Exception
 74→     */
 75→    public function serializeSubContingentResponse(array $response): SubContingent
 76→    {
 77→        $webinstance = $this->getWebinstance();
 78→
 79→        $subContingent = $this->em->getRepository(SubContingent::class)->findOneBy([
 80→            'externalId'  => $response['id'],
 81→            'webinstance' => $webinstance,
 82→        ]);
 83→
 84→        // Create object SubContingent if $subContingent not exists or update it if exists
 85→        if (null === $subContingent) {
 86→            $subContingent = new SubContingent();
 87→        }
 88→
 89→        $subContingent->setLabel($response['label'])
 90→                ->setDailyBooking($response['dailyBooking'])
 91→                ->setDate(new \DateTime($response['date']))
 92→                ->setExternalId($response['id'])
 93→                ->setLabel($response['label'])
 94→                ->setQuotaAvailable($response['quotaAvailablePublic'] - $response['quotaInUsePublic'])
 95→                ->setQuotaInUse($response['quotaInUsePublic'])
 96→                ->setType(ExternalBookingProvider::ELIBERTY_BOOKING)
 97→                ->setLimitQuotaOrderVel($response['limitQuotaOrderPublicVel'])
 98→                ->setSalesClosedAt(new \DateTime($response['closedAt']))
 99→                ->setPosition($response['position']);
100→
101→        if (isset($response['isQuotaUnlimitedForPublic'])) {
102→            $subContingent->setQuotaUnlimited((bool) $response['isQuotaUnlimitedForPublic']);
103→        }
104→
105→        if (isset($response['quotaUnlimitedForPublic'])) {
106→            $subContingent->setQuotaUnlimited((bool) $response['quotaUnlimitedForPublic']);
107→        }
108→
109→        $subContingent->setWebinstance($webinstance);
110→
111→        return $subContingent;
112→    }
113→
114→    /**
115→     * @param array                $response
116→     * @param SubContingent|null   $subContingent
117→     * @param ExternalBooking|null $externalBooking
118→     *
119→     * @return ExternalBooking
120→     *
121→     * @throws \Exception
122→     */
123→    public function serializeExternalBookingResponse(array $response, SubContingent $subContingent = null, ExternalBooking $externalBooking = null): ExternalBooking
124→    {
125→        // Create object ExternalBooking if $externalBooking not exists or update it if exists
126→        if (null === $externalBooking) {
127→            $externalBooking = new ExternalBooking();
128→
129→            if (null !== $subContingent) {
130→                $externalBooking->setSubContingent($subContingent);
131→            }
132→        }
133→
134→        $status = 'init'      === $response['orderState'] ? ExternalBookingState::INIT : null;
135→        $status = 'cart'      === $response['orderState'] ? ExternalBookingState::CART : $status;
136→        $status = 'confirmed' === $response['orderState'] ? ExternalBookingState::CONFIRMED : $status;
137→        $status = 'cancelled' === $response['orderState'] ? ExternalBookingState::CANCELLED : $status;
138→
139→        $externalBooking->setExternalId($response['id'] ?? $externalBooking->getExternalId())
140→                ->setType(ExternalBookingProvider::ELIBERTY_BOOKING)
141→                ->setExternalReference($response['bookingReference'])
