 5→use EightPoints\Guzzle\WsseAuthMiddleware;
 6→use Eliberty\ConfigManagerBundle\Model\ConfigManager;
 7→use GuzzleHttp\Client;
 8→use GuzzleHttp\HandlerStack;
 9→
10→/**
11→ * Class ClientFactory.
12→ */
13→class ClientFactory
14→{
15→    private ConfigManager $configManager;
16→
17→    public function __construct(ConfigManager $manager)
18→    {
19→        $this->configManager = $manager;
20→    }
21→
22→    public function getClient(): Client
23→    {
24→        $cfg      = $this->configManager->getByNamespace('booking.guzzle_config');
25→        $username = $this->configManager->getStringOption('booking.wsse_username');
26→        $password = $this->configManager->getStringOption('booking.wsse_password');
27→
28→        $clientConfig = [];
29→        foreach ($cfg as $k => $v) {
30→            $simplified_key                = substr($k, strrpos($k, '.') + 1);
31→            $clientConfig[$simplified_key] = $v;
32→        }
33→
34→        $clientConfig['defaults'] = [];
35→        $clientConfig['base_uri'] = $clientConfig['base_url'];
36→        unset($clientConfig['base_url']);
37→
38→        $useProxy = $this->configManager->getBoolOption('guzzle.debug', false);
39→        $proxyUrl = $this->configManager->getStringOption('guzzle.proxy_url', 'tcp://localhost:8080');
40→
41→        if ($useProxy) {
42→            $clientConfig['defaults']['proxy'] = $proxyUrl;
43→        }
44→
45→        $wsse = new WsseAuthMiddleware($username, $password);
46→        $wsse->setCreatedAtTimeExpression('-10 seconds');
47→        $stack = HandlerStack::create();
48→        $stack->push($wsse->attach());
49→
50→        $clientConfig['handler'] = $stack;
51→
52→        return new Client($clientConfig);
53→    }
