 45→    public function getDaysAvailability(Product $product): array
 46→    {
 47→        $result = [];
 48→        /** @var Season $currentSeason */
 49→        $currentSeason = $this->em->getRepository(Season::class)->getCurrentSeason();
 50→        $seasonEndDate = $currentSeason->getEndDate();
 51→        $date          = Carbon::now();
 52→
 53→        while ($date <= $seasonEndDate) {
 54→            $date     = clone $date;
 55→            $result[] = $date->format('Y-m-d');
 56→            $date->add(new \DateInterval('P1D'));
 57→        }
 58→
 59→        return $result;
 60→    }
