 63→     * @throws ExternalActivityException
 64→     */
 65→    public function getSubContingentsBetweenDates(Product $product, \DateTime $startDate, \DateTime $endDate = null): array
 66→    {
 67→        try {
 68→            $result = $this->restFactory->askReservation($product, $startDate);
 69→            if (null !== $result && !$result->error && 'yes' === $result->resa_possible) {
 70→                return $this->helper->getSubContingents($product, $startDate)->toArray();
 71→            }
 72→
 73→            throw new ExternalActivityException(sprintf('Koralp booking - out of sale for this day. Date : %s | Koralp : %s', $startDate->format('Y-m-d'), $product->getExternalActivityResourceId()));
 74→        } catch (\Exception $e) {
 75→            $this->helper->parseAndLogException(__METHOD__, $e);
 76→
 77→            throw new ExternalActivityException($e);
 78→        }
 79→    }
