 87→        /** @var SubContingent $subContingent */
 88→        $subContingent = $this->helper->getSubContingent($subContingentId);
 89→
 90→        if (null === $subContingent) {
 91→            $e = new \Exception(sprintf('Koralp booking - subContingent not found with %s identifier', $subContingentId));
 92→            $this->helper->parseAndLogException(__METHOD__, $e);
 93→
 94→            throw new ExternalActivityException($e);
