100→    /**
101→     * @throws \SoapFault
102→     * @throws ExternalActivityException
103→     */
104→    public function createBooking(Order $order, SubContingentData $subContingentData): ExternalBooking
105→    {
106→        $this->logger->debug(sprintf('Koralp create booking on order %d for sub contingent %d with qty %d',
107→            $order->getId(), $subContingentData->getSubContingentId(), $subContingentData->getQty()));
108→
109→        $product         = $subContingentData->getProduct();
110→        $date            = $subContingentData->getDate();
111→        $subContingentId = $subContingentData->getSubContingentId();
112→
113→        if (null === $subContingent = $this->helper->getSubContingent($subContingentId)) {
114→            throw new ExternalActivityException(sprintf('Koralp booking - subcontingent not found : %s', $subContingentId));
115→        }
116→
117→        $quantity = $subContingentData->getQty();
118→        $maxQuota = $product->getMaxQuotaPerCart();
119→        if (!empty($maxQuota) && $quantity > $maxQuota) {
120→            throw new ExternalActivityException(sprintf('Koralp booking - max quota for product %d is %d', $product->getId(), $maxQuota));
121→        }
122→
123→        $response = $this->restFactory->confirmReservation($product, $date, $quantity);
124→        if (null === $response || 'no' === $response->resa_possible || 0 !== $response->error || empty($response->commande)) {
125→            $message = isset($response) && !empty($response->msgerror) ?
126→                sprintf('Koralp booking - confirmation error: resa is not possible - %s', $response->msgerror) :
127→                'Koralp booking - confirmation error: resa is not possible';
128→            throw new ExternalActivityException($message);
129→        }
130→
131→        $subContingent->setQuotaInUse($quantity);
132→        $this->helper->updateItemsData($subContingent->getExternalId(), $subContingentData, $response);
133→        $externalBooking = $this->findBookingBySubContingent($subContingent, $order->getWebinstance());
134→
135→        return $this->helper->serializeExternalBookingResponse($response, $order->getId(), $subContingent, $externalBooking);
136→    }
