138→    public function synchronizeBooking(Order $order, ExternalBooking $externalBooking): ExternalBooking
139→    {
140→        return $this->findBooking($externalBooking->getExternalId(), $order->getWebinstance());
141→    }
142→
143→    /**
144→     * @throws \SoapFault
145→     */
146→    public function confirmBooking(Order $order, ExternalBooking $externalBooking): ExternalBooking
147→    {
148→        $this->logger->info(sprintf('Koralp confirm booking on order %d for external booking %d and qty %d',
149→            $order->getId(), $externalBooking->getId(), $externalBooking->getCount()));
150→
151→        /** @var ?ContactInterface $payer */
152→        $payer = $order->getContact();
153→
154→        if (null !== $payer) {
155→            $phone = $payer->getMobile() ?: $payer->getPhone();
156→            $externalBooking->setAuthorFirstname($payer->getFirstname());
157→            $externalBooking->setAuthorLastname($payer->getLastname());
158→            $externalBooking->setAuthorMail($payer->getEmail());
159→            $externalBooking->setAuthorPhone($phone);
160→        }
161→
162→        $skicaseOrderitems = $order->getOrderitems()->filter(function (Orderitem $orderitem) {
163→            return ProductType::SKICASE === $orderitem->getType();
164→        });
165→
166→        $failed   = false;
167→        $commands = $contractors = [];
168→        foreach ($skicaseOrderitems as $skicaseOrderitem) {
169→            $data = $skicaseOrderitem->getData();
170→            if (\array_key_exists('koralp', $data)) {
171→                ['contractorId' => $contractorId, 'webId' => $webId, 'commandId' => $commandId] = $data['koralp'];
172→                if (\in_array($commandId, $commands, true)) {
173→                    continue;
174→                }
175→                if (!\in_array($contractorId, $contractors, true)) {
176→                    $contractors[$contractorId] = $this->em->getRepository(Contractor::class)->find($contractorId);
177→                }
178→
179→                $response = $this->restFactory->confirmPayment($contractors[$contractorId], $skicaseOrderitem->getProduct(), $webId, $commandId, $payer);
180→                if (null === $response || 0 !== $response->error || 'confirm' !== $response->etat) {
181→                    $this->logger->error(sprintf('Koralp confirm payment error for order item %d', $skicaseOrderitem->getId()), [
182→                        'koralp_data' => $data['koralp'],
183→                        'response'    => $response,
184→                    ]);
185→                    $failed = true;
186→                }
187→                $commands[] = $commandId;
188→            }
189→        }
190→
191→        if (!empty($commands) && !$failed) {
192→            $this->logger->info(sprintf('Koralp confirm payment succeeded on order %d for external booking %d', $order->getId(), $externalBooking->getId()), [
193→                'commands' => $commands,
194→            ]);
195→            $externalBooking->setStatus(ExternalBookingState::CONFIRMED);
196→        }
197→
198→        return $externalBooking;
199→    }
