202→     * @param Orderitem|TicketOrderitem|null $item
203→     */
204→    public function findBooking(string $externalBookingId, WebInstance $webInstance, OrderitemInterface $item = null): ?ExternalBooking
205→    {
206→        $criterias = [
207→            'externalId'  => $externalBookingId,
208→            'webinstance' => $webInstance,
209→        ];
210→
211→        /** @var ?ExternalBooking $externalBooking */
212→        $externalBooking = $this->em->getRepository(ExternalBooking::class)->findOneBy($criterias);
213→
214→        if (null === $externalBooking) {
215→            $this->helper->logInfo(sprintf('No booking found for this external booking id %s', $externalBookingId));
216→        }
217→
218→        return $externalBooking;
219→    }
