226→        ];
227→
228→        /** @var ?ExternalBooking $externalBooking */
229→        $externalBooking = $this->em->getRepository(ExternalBooking::class)->findOneBy($criterias);
230→
231→        if (null === $externalBooking) {
232→            $this->helper->logInfo(sprintf('No booking found for this sub contingent id %s', $subContingent->getId()));
233→        }
234→
235→        return $externalBooking;
