 57→    public function serializeExternalBookingResponse(object $response, int $orderId, SubContingent $subContingent, ExternalBooking $externalBooking = null): ExternalBooking
 58→    {
 59→        // Create object ExternalBooking if not exists or update it.
 60→        if (null === $externalBooking) {
 61→            $externalBooking = new ExternalBooking();
 62→        }
 63→
 64→        $status = 'yes' === $response->resa_possible ? ExternalBookingState::INIT : null;
