 49→    public function getSubContingentsBetweenDates(Product $product, \DateTime $startDate, ?\DateTime $endDate): array
 50→    {
 51→        try {
 52→            $params   = $this->apiHelper->getParamActivitiesBetweenDates($product, $startDate);
 53→            $cacheKey = $this->apiHelper->getRedisKey('teamaxess_subcontigent', '', $params);
 54→
 55→            if (!$data = $this->redisCache->get($cacheKey)) {
 56→                $data = $this->contingentClient->getContingents($params);
 57→
 58→                $cacheTime = $this->apiHelper->getCacheExpirationTime();
 59→                if ($cacheTime > 0) {
 60→                    $this->redisCache->set($cacheKey, $data, $cacheTime);
 61→                }
 62→            }
