 76→     * @param \DateTime $startDate
 77→     * @param string    $subContingentId
 78→     * @param bool|null $withCache
 79→     *
 80→     * @return SubContingent
 81→     *
 82→     * @throws ExternalActivityException
 83→     */
 84→    public function getSubContingent(Product $product, \DateTime $startDate, string $subContingentId, ?bool $withCache = false): ?SubContingent
 85→    {
 86→        try {
 87→            $params         = $this->apiHelper->getParamSubContingent($product, $startDate, $subContingentId);
 88→            $cacheKey       = $this->apiHelper->getRedisKey('teamaxess_subcontigent', '', $params);
 89→            $fromRedisCache = true;
 90→
 91→            if (!$data = $this->redisCache->get($cacheKey)) {
 92→                $data = $this->contingentClient->getContingents($params);
 93→
 94→                if ($this->apiHelper->getCacheExpirationTime() > 0) {
 95→                    $this->redisCache->set($cacheKey, $data, $this->apiHelper->getCacheExpirationTime());
 96→                }
 97→
 98→                $fromRedisCache = false;
