127→            $params   = $this->apiHelper->getParamForCreateBooking($order, $subContingentData);
128→            $response = $this->contingentClient->lockReservation($params);
129→
130→            if (true === $response['success']) {
131→                return $this->apiHelper->serializeExternalBookingResponse($response, $subContingentData, $order);
132→            }
133→
134→            throw new ExternalActivityException('TA booking error - reservation lock failure');
135→        } catch (CommandException | \Exception $e) {
136→            $this->apiHelper->parseAndLogException(__METHOD__, $e);
137→
138→            throw new ExternalActivityException($e);
139→        }
140→    }
