142→    public function synchronizeBooking(Order $order, ExternalBooking $externalBooking): ExternalBooking
143→    {
144→        $item = $this->findFirstMachingOrderitem($order, $externalBooking);
145→
146→        return $this->findBooking($externalBooking->getExternalId(), $order->getWebinstance(), $item);
147→    }
