149→    public function confirmBooking(Order $order, ExternalBooking $externalBooking): ExternalBooking
150→    {
151→        $item = $this->findFirstMachingOrderitem($order, $externalBooking);
152→
153→        return $this->findBooking($externalBooking->getExternalId(), $order->getWebinstance(), $item);
154→    }
155→
156→    private function findFirstMachingOrderitem(Order $order, ExternalBooking $externalBooking): ?OrderitemInterface
157→    {
158→        $items = $order->getItemsWithExternalBookings()->filter(function (OrderitemInterface $item) use ($externalBooking) {
159→            /** @var Orderitem|TicketOrderitem $item */
160→            if (null === $externalBooking->getSubContingent()) {
161→                return $externalBooking->getExternalId() === $item->getDatum('externalBookingId');
162→            }
163→
164→            return $externalBooking->getExternalId() === $item->getDatum('externalBookingId')
165→                && $externalBooking->getSubContingent()->getExternalId() === $item->getDatum('subContingentId');
166→        });
167→
168→        if (0 === $items->count()) {
169→            $this->apiHelper->logInfo('No orderitem found (one expected) for externalBooking '.$externalBooking->getId());
170→        }
171→
172→        return $items->first() ?: null;
173→    }
