175→    /**
176→     * @param Orderitem|TicketOrderitem|null $item
177→     */
178→    public function findBooking(string $externalBookingId, WebInstance $webInstance, ?OrderitemInterface $item = null): ?ExternalBooking
179→    {
180→        if (null === $item) {
181→            throw new ExternalActivityException('Orderitem is missing');
182→        }
183→
184→        if (!$subContingentId = $item->getDatum('subContingentId')) {
185→            throw new ExternalActivityException('No subContingentId TA found in order item '.$item->getId());
186→        }
187→
188→        $criterias = [
189→            'externalId'  => $subContingentId,
190→            'webinstance' => $webInstance,
191→        ];
192→
193→        $subContingent = $this->em->getRepository(SubContingent::class)->findOneBy($criterias);
194→
195→        $criterias = [
196→            'externalId'    => $externalBookingId,
197→            'subContingent' => $subContingent,
198→            'webinstance'   => $webInstance,
199→        ];
200→
201→        /** @var ExternalBooking|null $booking */
202→        $booking = $this->em->getRepository(ExternalBooking::class)->findOneBy($criterias, ['id' => 'DESC']);
203→
204→        if (null === $booking) {
205→            $this->apiHelper->logInfo('no booking found for this externalBookingId in redpill database.', $criterias);
206→            $this->apiHelper->logInfo('Call booking application to check if this order exist', ['booking_id' => $externalBookingId]);
207→        }
208→
209→        return $booking;
210→    }
211→}
