 18→use Eliberty\RedpillBundle\ExternalActivity\Helpers\BaseApiHelper;
 19→use Eliberty\RedpillBundle\ExternalActivity\Models\SubContingentData;
 20→use GuzzleHttp\Command\Result;
 21→use Monolog\Logger;
 22→
 23→/**
 24→ * Class ApiHelper.
 25→ */
 26→class ApiHelper extends BaseApiHelper
 27→{
 28→    private const LIMIT_QUOTA_ORDER_VEL = 99;
 29→    private const TIMEOUT               = 40; // 40 min
 30→
 31→    public function __construct(ConfigManager $configManager, EntityManagerInterface $em, Logger $loggerBooking)
 32→    {
 33→        parent::__construct($configManager, $em, $loggerBooking);
 34→    }
 35→
 36→    public function getSubContingents(Result $contingent, \DateTime $startDate = null, \DateTime $endDate = null): ArrayCollection
 37→    {
 38→        $result             = new ArrayCollection();
 39→        $now                = Carbon::now();
 40→        $repo               = $this->em->getRepository(SubContingent::class);
 41→        $contingentsToFlush = false;
 42→
 43→        $today = new \DateTime('now', new \DateTimeZone('UTC'));
 44→        $today->setTime($now->hour, $now->minute);
 45→
 46→        if (!\array_key_exists('sub_contingents', $contingent->toArray())) {
 47→            return $result;
 48→        }
 49→
 50→        foreach ($contingent['sub_contingents'] as $apiSubContingent) {
 51→            $date = substr($apiSubContingent['start_time'], 0, strpos($apiSubContingent['start_time'], '+'));
 52→
 53→            try {
 54→                $date = new \DateTime(str_replace('T', ' ', $date), new \DateTimeZone('UTC'));
 55→            } catch (\Exception $e) {
 56→                $date = clone $today;
 57→            }
 58→
 59→            if ($date < $today) {
 60→                continue;
 61→            }
 62→
 63→            // check if date is between startdate and enddate
 64→            if ($startDate && $endDate && !(($date >= $startDate) && ($date <= $endDate))) {
 65→                continue;
 66→            }
 67→
 68→            $strDate     = $date->format('Y').'-'.$date->format('m').'-'.$date->format('d');
 69→            $externalId  = $contingent['contingent_number'].'_'.$apiSubContingent['sub_contingent_number'].'_'.$strDate;
 70→            $webinstance = $this->getWebinstance();
 71→
 72→            $subContingent = $repo->findOneBy([
 73→                'externalId'  => $externalId,
 74→                'webinstance' => $webinstance,
 75→            ]);
 76→
 77→            // Create object SubContingent if $subContingent not exists or update it if exists
 78→            if (null === $subContingent) {
 79→                $subContingent = new SubContingent();
 80→                $subContingent
 81→                    ->setWebinstance($webinstance)
 82→                    ->setExternalId($externalId);
 83→                $this->em->persist($subContingent);
 84→                $contingentsToFlush = true;
 85→            }
 86→
 87→            $subContingent
 88→                ->setQuotaAvailable($apiSubContingent['ticket_count_free'])
 89→                ->setQuotaInUse($apiSubContingent['ticket_count_sold'] + $apiSubContingent['ticket_count_locked'])
 90→                ->setDate($date)
 91→                ->setLabel($apiSubContingent['sub_contingent_name'])
 92→                ->setPosition($apiSubContingent['sub_contingent_number'])
 93→                ->setType(ExternalBookingProvider::TEAMAXESS_RESERVATION)
 94→                ->setLimitQuotaOrderVel(self::LIMIT_QUOTA_ORDER_VEL)
 95→                ->setDuration((int) $apiSubContingent['duration_in_minutes'])
 96→                ->setShortname($apiSubContingent['sub_contingent_shortname'])
 97→                ->setSalesClosedAt($date);
 98→
 99→            $result->add($subContingent);
100→        }
101→
102→        // order collection items by position property
103→        $orderBy = Criteria::create()->orderBy([
104→            'date' => Criteria::ASC,
105→        ]);
106→
107→        if ($contingentsToFlush) {
108→            $this->em->flush();
109→        }
110→
111→        // return sorter SomeCollectionItem array
112→        return $result->matching($orderBy);
113→    }
114→
115→    public function serializeSubContingentResponse(Result $contingent): ?SubContingent
116→    {
117→        $res = $this->getSubContingents($contingent);
118→
119→        if ($res->isEmpty()) {
120→            return null;
121→        }
122→
123→        return $res->first();
124→    }
125→
126→    public function serializeExternalBookingResponse(
127→        Result $result,
128→        SubContingentData $subContingentData,
129→        Order $order
130→    ): ExternalBooking {
131→        $externalBooking = new ExternalBooking();
132→
133→        $criterias = [
134→            'externalId'  => $subContingentData->getSubContingentId(),
135→            'webinstance' => $order->getWebinstance(),
136→        ];
137→
138→        $subContingent = $this->em->getRepository(SubContingent::class)->findOneBy($criterias);
139→
140→        if (null === $subContingent) {
141→            throw new ExternalActivityException(sprintf('SubContingent not found with criterias externalId=%s and webinstance=%s', $subContingentData->getSubContingentId(), $order->getWebinstance()));
142→        }
143→
144→        $externalBooking->setExternalId($subContingentData->getExternalBookingId())
145→            ->setType(ExternalBookingProvider::TEAMAXESS_RESERVATION)
146→            ->setExternalReference($result['reference'])
147→            ->setLabel($subContingent->getLabel())
148→            ->setStatus(ExternalBookingState::INIT)
149→            ->setCount($subContingentData->getQty())
150→            ->setWebinstance($this->getWebinstance())
151→            ->setAuthorLocale($order->getLocale())
152→            ->setSubContingent($subContingent);
153→
154→        return $externalBooking;
155→    }
