157→    public function getParamActivitiesBetweenDates(Product $product, \DateTime $startDate): array
158→    {
159→        $contingentId = $product->getExternalActivityResourceId();
160→
161→        $scConfiguration = $this->em->getRepository(SaleschannelConfiguration::class)
162→            ->findOneBy(['catalog' => $product->getCatalog()->getId()]);
163→
164→        return [
165→            'saleschannel' => (int) $scConfiguration->getSaleschannelExternalid(),
166→            'contingent'   => (int) $contingentId,
167→            'startdate'    => $startDate->format('Y-m-d'),
168→        ];
169→    }
170→
171→    public function getParamSubContingent(Product $product, \DateTime $startDate, string $subContingentId): array
172→    {
173→        $contingentId = $product->getExternalActivityResourceId();
174→
175→        $scConfiguration = $this->em->getRepository(SaleschannelConfiguration::class)
176→            ->findOneBy(['catalog' => $product->getCatalog()->getId()]);
177→
178→        $subContingent = explode('_', $subContingentId)[1];
179→
180→        return [
181→            'saleschannel'  => (int) $scConfiguration->getSaleschannelExternalid(),
182→            'contingent'    => (int) $contingentId,
