188→    public function getParamForCreateBooking(Order $order, SubContingentData $subContingentData): array
189→    {
190→        $product = $subContingentData->getProduct();
191→
192→        $scConfiguration = $this->em->getRepository(SaleschannelConfiguration::class)
193→            ->findOneBy(['catalog' => $product->getCatalog()->getId()]);
194→
195→        $externalId = $subContingentData->getSubContingentId();
196→
197→        [$contingent, $subContingent] = explode('_', $externalId);
198→
199→        $reference = $order->getId();
200→
201→        if (false === $this->configManager->getBoolOption('booking.orderid_as_booking_externalid', true)) {
202→            $reference = $contingent.$subContingent.$subContingentData->getDate()->format('Ymd').$order->getId();
203→        }
204→
205→        $reference = str_pad($reference, 24, '0', \STR_PAD_LEFT);
206→
207→        $subContingentData->setExternalBookingId($reference);
208→
209→        return [
210→            'saleschannel'  => $scConfiguration->getSaleschannelExternalid(),
211→            'contingent'    => $contingent,
212→            'subcontingent' => $subContingent,
213→            'startdate'     => $subContingentData->getDate()->format('Y-m-d'),
214→            'counter'       => $subContingentData->getQty(),
215→            'reference'     => $reference,
216→            'timeout'       => self::TIMEOUT,
217→        ];
218→    }
219→}
