 38→        $this->em                             = $em;
 39→    }
 40→
 41→    private function getHandler(string $provider): ?ExternalActivityHandlerInterface
 42→    {
 43→        if (!isset($this->handlers[$provider])) {
 44→            $this->handlers[$provider] = $this->externalActivityHandlerFactory->getHandler($provider);
 45→        }
 46→
 47→        return $this->handlers[$provider];
 48→    }
 49→
 50→    private function getHandlerByProduct(Product $product): ?ExternalActivityHandlerInterface
 51→    {
 52→        $provider = $product->getExternalBookingProvider();
 53→
 54→        return null !== $provider ? $this->getHandler($provider) : null;
 55→    }
 56→
 57→    /**
 58→     * @throws ExternalActivityException
 59→     */
 60→    public function getDaysAvailability(Product $product): array
 61→    {
 62→        $referenceTicketDates = $this->getDatesByReferenceTicket($product);
 63→        if (\is_array($referenceTicketDates) && \count($referenceTicketDates)) {
 64→            return $referenceTicketDates;
 65→        }
 66→
 67→        return $this->getHandlerByProduct($product)->getDaysAvailability($product);
 68→    }
 69→
 70→    /**
 71→     * @throws \DateMalformedPeriodStringException
 72→     */
 73→    private function getDatesByReferenceTicket(Product $product): ?array
 74→    {
 75→        if (false === $product->isUseReferenceTicketForCalendar()
 76→                || null === $currentRequest = $this->requestStack->getCurrentRequest()) {
 77→            return null;
 78→        }
 79→
 80→        $slug             = $currentRequest->get('slug');
 81→        $startDate        = $currentRequest->get('s');
 82→        $referenceProduct = $this->em->getRepository(Product::class)->getBySlug($slug);
 83→        if (null === $slug || null === $startDate || null === $referenceProduct || null === $referenceProduct->getValiditycategory()
 84→                || null === $valcatValue = $referenceProduct->getValiditycategory()->getValue()) {
 85→            return null;
 86→        }
 87→
 88→        $carbonStartdate = Carbon::createFromFormat('Y-m-d', $startDate)->setTime(0, 0);
 89→        $carbonEnddate   = (clone $carbonStartdate)->addDays($valcatValue);
 90→
 91→        $period = new \DatePeriod(
 92→            $carbonStartdate,
 93→            new \DateInterval('P1D'),
 94→            $carbonEnddate
 95→        );
 96→
 97→        return array_map(
 98→            static function ($date) {
 99→                return $date->format('Y-m-d');
100→            },
101→            iterator_to_array($period)
102→        );
103→    }
104→
105→    /**
106→     * @throws ExternalActivityException
107→     * @throws \RedisException
108→     */
109→    public function getSubContingentsBetweenDates(Product $product, \DateTime $startDate, ?\DateTime $endDate): array
110→    {
111→        $handler = $this->getHandlerByProduct($product);
112→        if (null === $handler) {
113→            throw new ExternalActivityException(sprintf('Booking service error: no handler available for specified product %s', $product->getSlug()));
114→        }
115→
116→        $externalActivities = $handler->getSubContingentsBetweenDates($product, $startDate, $endDate);
117→
118→        usort($externalActivities, static function (SubContingent $a, SubContingent $b) {
119→            return ($a->getDate() < $b->getDate()) ? -1 : 1;
120→        });
121→
122→        $result = [];
123→
124→        $showSubcontingentCompleted = $this->configManager->getBoolOption('booking.show_subcontingent_completed', true);
125→        /** @var SubContingent $subContingent */
126→        foreach ($externalActivities as $subContingent) {
127→            if ($showSubcontingentCompleted || $subContingent->getQuotaAvailable() > 0 || $subContingent->isQuotaUnlimited()) {
128→                $result[] = $subContingent;
129→            }
130→        }
131→
132→        return $result;
133→    }
134→
135→    /**
136→     * @throws ExternalActivityException
137→     */
138→    public function checkSubContingentAvailability(Product $product, \DateTime $startDate, string $subContingentId, int $qtyUsed): bool
139→    {
140→        $subContingent = $this->getHandlerByProduct($product)->getSubContingent($product, $startDate, $subContingentId);
141→
142→        if (null === $subContingent) {
143→            return false;
144→        }
145→
146→        $quotaSiteLimit   = $subContingent->getLimitQuotaOrderVel() ?? self::QTY_MAX;
147→        $isQuotaUnlimited = $subContingent->isQuotaUnlimited();
148→        $availability     = $subContingent->getQuotaAvailable();
149→        $availability     = min(max($availability, 0), $quotaSiteLimit);
